INSERT INTO public.photos VALUES (23138, 'Rastro 2006', 'Foto: Marâ”œآ،a Torres-Solanot. Vista del rastro instalado en el aparcamiento del pabellâ”œâ”‚n Prâ”œآ،ncipe Felipe (al fondo), el miâ”œآ®rcoles 19 de abril de 2006. Es su primer dâ”œآ،a en esa ubicaciâ”œâ”‚n, y todavâ”œآ،a tiene pocos puestos, debido a la oposiciâ”œâ”‚n por parte de algunos de sus comerciantes a trastadarse allâ”œآ،, desde el entorno de La Romareda. El domingo 30 de abril ya estarâ”œأ­n todos. En 2008 serâ”œأ­ trasladado a La Almozara; tambiâ”œآ®n el de la plaza de Toros. Fuente: Heraldo de Aragâ”œâ”‚n.', 2006, 2006, 2006, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.63668300, -0.86605500, '0101000020E61000006631B1F9B8B6EBBFA7751BD47ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31819809201.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31819809201.webp', 'https://www.flickr.com/photos/zaragozaantigua/31819809201/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23152, 'Miraflores 2009', 'Imagen virtual del "Nuevo campo municipal de fâ”œâ•‘tbol de Zaragoza", proyectado en la pastilla delimitada por el cinturâ”œâ”‚n de Ronda (N), la acequia del Ojo del Gallo (O), y el tendido ferroviario proveniente de la estaciâ”œâ”‚n de Miraflores (E). Segâ”œâ•‘n las bases del concurso internacional, el nuevo campo deberâ”œآ،a tener capacidad hasta las 50000 plazas, en un entorno de actividades complementarias como restaurantes, comercios y recreativos, y flanqueado por dos edificios de 26 plantas de VPO, otro de 21 plantas, dos mâ”œأ­s de 16, uno de 14, y varios de 4. Completaban el panorama 12 bloques de 9 plantas con viviendas libres, para alcanzar los 3.422 pisos nuevos (2.530 libres y 892 VPO), ademâ”œأ­s de 2.500 plazas de aparcamiento. El proyecto ganador, el de la imagen, introducâ”œآ،a alguna variante en las torres de monopoly previstas, si bien el devenir de las cosas dejâ”œâ”‚ el asunto, que deberâ”œآ،a haber estado finalizado en 2011, en suspenso. Aunque sâ”œâ”‚lo sea una recreaciâ”œâ”‚n virtual, nunca se habâ”œآ،a visto este entorno tan ferazmente verde desde los tiempos de la antigua Granja Agrâ”œآ،cola. Desde la atalaya de 26 pisos seguro que se verâ”œآ،a bien el camino de Miraflores. Fuente visual: siciliayasociados.com/', 2009, 2009, 2009, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.63046000, -0.86622200, '0101000020E61000003C6C223317B8EBBFD4B7CCE9B2D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32281056915.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32281056915.webp', 'https://www.flickr.com/photos/zaragozaantigua/32281056915/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23178, 'Talleres Diâ”œآ®sel 2000', 'Aspecto del edificio de Talleres Diâ”œآ®sel S.A., en la calle de Miguel Servet 216. Factorâ”œآ،a de bombas inyectoras para motores diâ”œآ®sel fundada por Pedro Esteban como Transformaciones Diâ”œآ®sel S.A. en 1939. Se demoliâ”œâ”‚ en 2006. Fuente: Foto de Jacob Gragera.', 2000, 2000, 2000, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.63685900, -0.86415400, '0101000020E610000087A4164A26A7EBBFE694809884D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36914919355.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36914919355.webp', 'https://www.flickr.com/photos/zaragozaantigua/36914919355/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23183, 'Miraflores c.2000', 'Imagen capturada desde la metâ”œأ­lica pasarela peatonal que salvaba las vâ”œآ،as del ferrocarril junto a la estaciâ”œâ”‚n de Miraflores, y permitâ”œآ،a el acceso a sus andenes. Raudo y a â”œâ•‘ltima hora de la tarde pasa el tren de media distancia o servicio Regional con destino a Binâ”œآ®far servido por un automotor ligero de la serie 596 de los conocidos como "Tamagochis" por su pequeâ”œâ–’o tamaâ”œâ–’o. A la derecha y tras el tren, la antigua estaciâ”œâ”‚n de Miraflores, y algo detrâ”œأ­s el tradicional edificio de viviendas de la estaciâ”œâ”‚n. Poco despuâ”œآ®s, la pasarela metâ”œأ­lica serâ”œآ،a retirada con motivo de las obras de construcciâ”œâ”‚n del tercer cinturâ”œâ”‚n de ronda, y unos aâ”œâ–’os despuâ”œآ®s este entorno serâ”œآ،a radicalmente remodelado durante el soterramiento de las vâ”œآ،as, que supusieron el derribo de los edificios del entorno, salvo la moderna estaciâ”œâ”‚n transformadora que se deja ver tras el pintarrajeado edificio de la antigua estaciâ”œâ”‚n.', 2000, 2000, 2000, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.63238000, -0.86676100, '0101000020E61000001D588E9081BCEBBF7E52EDD3F1D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51035209446.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51035209446.webp', 'https://www.flickr.com/photos/zaragozaantigua/51035209446/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23235, 'Giesa 2023', 'Vista de la nueva plaza inaugurada por el alcalde Jorge Azcâ”œâ”‚n en 2023, fruto de acondicionar el solar del derribo de las naves norte y central de la antigua factorâ”œآ،a Giesa, luego Schindler, entre las calles del Padre Chaminade, a la izquierda, y de Yolanda de Bar, a la derecha. Al fondo se ve el palacio de Larrinaga, en la calle de Miguel Servet, y la torre de pruebas de ascensores de la fâ”œأ­brica, a la derecha. A esta plaza se le llamâ”œâ”‚ "plaza de Giesa" y "plaza de Vicente Cazcarra", por ser el punto donde termina el paseo homâ”œâ”‚nimo. De 4.200 metros cuadrados, estaba equipada con zona de juegos infantiles, gimnasio al aire libre, pista multideporte, toldos, papeleras y alcorques para â”œأ­rboles. Fue derribada en 2025 para la construcciâ”œâ”‚n de una "ciudad del cine" llamada Distrito 7.', 2023, 2023, 2023, 'Siglo XXI', 'SAN JOSâ”œأ«', 41.63979100, -0.86481100, '0101000020E6100000E412471E88ACEBBF38A3E6ABE4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54452473437.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54452473437.webp', 'https://www.flickr.com/photos/zaragozaantigua/54452473437/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23444, 'Palacio de Larrinaga 1974', 'Tranvâ”œآ،a de la lâ”œآ،nea 1 recorre Miguel Servet junto al palacio de Larrinaga. Fuente: "Los tranvâ”œآ،as de Zaragoza", J. Peâ”œâ–’a/J. M. Valero, DPZ, 1985.', 1974, 1974, 1974, 'Anos 70', 'SAN JOSâ”œأ«', 41.63834300, -0.86441300, '0101000020E61000008997A77345A9EBBFB5503239B5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14953901031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14953901031.webp', 'https://www.flickr.com/photos/zaragozaantigua/14953901031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23448, 'La Granja 1974', 'Archivo Municipal Zaragoza. Gerardo Sancho Ramo. Mayo 1974. Imagen desde el interior de los terrenos de la antigua Granja Agrâ”œآ،cola. Los muros y la verja se corresponden con la entrada principal, que estaba en el Camino del Bajo Aragâ”œâ”‚n, luego Miguel Servet. Tras el abandono del proyecto de la Granja en 1943, los campos de herbâ”œأ­ceas y maâ”œآ،z continuaron siendo productivos hasta la urbanizaciâ”œâ”‚n de la zona, en la segunda mitad de los setenta. Al fondo, el abandonado Palacio de Larrinaga, que no levantaba cabeza desde el expolio y saqueo al que fue objeto durante y tras la guerra de 1936-1939.', 1974, 1974, 1974, 'Anos 70', 'SAN JOSâ”œأ«', 41.63810900, -0.86501200, '0101000020E6100000BFB854A52DAEEBBF4224438EADD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15062084399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15062084399.webp', 'https://www.flickr.com/photos/zaragozaantigua/15062084399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23479, 'Palacio de Larrinaga 1938', 'En octubre de 1937 fue creado el Cuerpo de Ejâ”œآ®rcito de Galicia, con soldados rebeldes, a las â”œâ”‚rdenes de Franco. A inicios de 1938 se establecieron en el palacio de Larrinaga de Zaragoza, desde donde se dirigieron a participar en la batalla de Teruel. En la imagen, sus miembros posando en la escalinata de acceso al edificio de la calle de Miguel Servet. Fuente: Fondo Documental Mario Blanco Fuentes. Museo Manuel Reimâ”œâ”‚ndez Portela.', 1938, 1938, 1938, 'Anos 30', 'SAN JOSâ”œأ«', 41.63841500, -0.86449700, '0101000020E6100000FFAECF9CF5A9EBBF4F232D95B7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36351692682.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36351692682.webp', 'https://www.flickr.com/photos/zaragozaantigua/36351692682/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23489, 'Ctra. de Castellâ”œâ”‚n c.1912', 'Imagen centrada en la original Villa Asunciâ”œâ”‚n o vivienda unifamiliar del vizcaâ”œآ،no Miguel Larrinaga diseâ”œâ–’ada por el arquitecto Fâ”œآ®lix Navarro Pâ”œآ®rez en los extensos terrenos que este naviero poseâ”œآ،a en este tramo de la carretera de Zaragoza a Castellâ”œâ”‚n. La câ”œâ•‘pula central que remata la caja de la escalera serâ”œآ،a poco despuâ”œآ®s sustituida por un cimborrio de planta octogonal diseâ”œâ–’ado por el arquitecto Fernando de Escondrillas, En primer tâ”œآ®rmino, dos caballerâ”œآ،as tiran de un carro ante la verja y pâ”œآ®rgola que delimita el ingreso a la villa. Al otro lado de la carretera y confrontando con ella, fuera de plano, se encontraba el acceso a la Granja Agrâ”œآ،cola de Zaragoza.', 1912, 1912, 1912, 'Anos 10', 'SAN JOSâ”œأ«', 41.63833800, -0.86501200, '0101000020E6100000BFB854A52DAEEBBFA3E5400FB5D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49990273208.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49990273208.webp', 'https://www.flickr.com/photos/zaragozaantigua/49990273208/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24088, 'Giesa 1966', 'Imagen tomada en el gran patio central de la fâ”œأ­brica Giesa durante una reuniâ”œâ”‚n informativa previa a las elecciones sindicales convocadas ese aâ”œâ–’o, en este caso para la renovaciâ”œâ”‚n reglamentaria de Enlaces Sindicales y Vocales del Jurado de este centro de trabajo. Giesa contaba con una activa presencia del clandestino sindicato Comisiones Obreras, militantes del Partido Comunista, tan hâ”œأ­bilmente mimetizados, que en la imagen no se pueden distinguir de los demâ”œأ­s trabajadores. Destaca el busto sobre pedestal de Joaquâ”œآ،n Guiral Palacio, fundador de la empresa y fallecido en 1950. Muchos aâ”œâ–’os despuâ”œآ®s, tras el cierre de esta factorâ”œآ،a, el busto pasâ”œâ”‚ a dependencias municipales, donde fue tomado prestado por los amigos de lo ajeno, hasta la fecha. Tras las altas naves del fondo, la calle de Yolanda de Bar. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1966, 1966, 1966, 'Anos 60', 'SAN JOSâ”œأ«', 41.63998400, -0.86430300, '0101000020E6100000C4B5DAC35EA8EBBF4CFBE6FEEAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/45499042765.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/45499042765.webp', 'https://www.flickr.com/photos/zaragozaantigua/45499042765/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24090, 'CDM La Granja 1984', 'Imagen capturada con motivo de la visita del alcalde Ramâ”œâ”‚n Sainz de Varanda y Jimâ”œآ®nez de la Iglesia a las reciâ”œآ®n inauguradas instalaciones de las piscinas de La Granja, dentro del Centro Deportivo Municipal del mismo nombre. La estampa recuerda a alguna de las mâ”œأ­s celebradas escenas corales cinematogrâ”œأ­ficas de Fellini, o de Berlanga, que queda mâ”œأ­s cerca, con una turbamulta sin soluciâ”œâ”‚n de continuidad conformada por policâ”œآ،as municipales, cargos institucionales, vecinos mayores, vecinos en paâ”œâ–’os menores, tancredos puros y duros, chavales y chavalas... La desolaciâ”œâ”‚n del entorno, como las montaâ”œâ–’as de ruinas que enmarcan la escena, producto del derribo de la antigua fâ”œأ­brica de briquetas y conglomerados de Minas y Ferrocarriles de Utrillas, pasan a un plano secundario, contingente, porque ya habâ”œآ،a piscinas, que era lo importante. Al fondo, en la calle de Miguel Servet se destaca la torre de la empresa Transformaciones Diesel S.A., Zaragoza, mâ”œأ­s tarde Talleres Diesel S.A., Zaragoza, que luego se trasladâ”œâ”‚ a un polâ”œآ،gono industrial. En 2006 esta torre fue demolida.', 1984, 1984, 1984, 'Anos 80', 'SAN JOSâ”œأ«', 41.63659800, -0.86831600, '0101000020E61000003FFED2A23EC9EBBF7959130B7CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46573118155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46573118155.webp', 'https://www.flickr.com/photos/zaragozaantigua/46573118155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24187, 'Estaciâ”œâ”‚n de Cappa 1894', 'Imagen de la Estaciâ”œâ”‚n de Zaragoza de la compaâ”œâ–’â”œآ،a MZA, que conservaba la antigua denominaciâ”œâ”‚n de "Cappa", por haber sido fundada por Leâ”œâ”‚n Cappa. En el momento de capturar la imagen, esta estaciâ”œâ”‚n era el punto de salida de la lâ”œآ،nea Zaragoza-Barcelona. Unos meses despuâ”œآ®s, con la apertura del apeadero de Miraflores, esta estaciâ”œâ”‚n quedâ”œâ”‚ unida a la de Campo Sepulcro mediante un provisional enlace. Cuando desde Miraflores fueron tendidos directamente los rieles en direcciâ”œâ”‚n a Barcelona, la Estaciâ”œâ”‚n de Cappa quedâ”œâ”‚ sin servicio, hasta que en 1901, la concesiâ”œâ”‚n de uso pasâ”œâ”‚ a la compaâ”œâ–’â”œآ،a Minas y Ferrocarrilles de Utrillas, que la volviâ”œâ”‚ a activar en septiembre de 1904 como terminal carbonera, hasta 1966. En la imagen, a la izquierda el primitivo depâ”œâ”‚sito de locomotoras. A la derecha, el edificio principal de la estaciâ”œâ”‚n. Fuente visual: www.plouteruel.com', 1894, 1894, 1894, 'Siglo XIX', 'SAN JOSâ”œأ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20206672749.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20206672749.webp', 'https://www.flickr.com/photos/zaragozaantigua/20206672749/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24189, 'Estaciâ”œâ”‚n de Utrillas 1904', 'Impulsada por el prâ”œâ”‚cer local Leâ”œâ”‚n Cappa, en 1865 comenzâ”œâ”‚ a funcionar la "Compaâ”œâ–’â”œآ،a del Ferrocarril de Zaragoza a Escatrâ”œâ”‚n", y â”œآ®l mismo diseâ”œâ–’â”œâ”‚ el edificio principal de la estaciâ”œâ”‚n terminal en Zaragoza, denominada "De Escatrâ”œâ”‚n", y levantada en la carretera de Alcaâ”œâ–’iz, mâ”œأ­s allâ”œأ­ del Molino del Seminario, entre la Torre de Ponte, y la de Mazas. En 1894 funcionâ”œâ”‚ provisionalmente como estaciâ”œâ”‚n de Zaragoza-Barcelona, hasta que se construyâ”œâ”‚ el empalme de Miraflores para conectar con la lâ”œآ،nea MZA. Ya tenâ”œآ،a como vecinas, al lado, las Dependencias de los Tranvâ”œآ،as, y cerca, la Granja Experimental, y el Matadero Municipal. En 1904 fue adquirida por la compaâ”œâ–’â”œآ،a "Minas y Ferrocarriles de Utrillas", que la habilitâ”œâ”‚ como terminal carbonera del ferrocarril de Utrillas-Montalbâ”œأ­n, y nueva sede social de la empresa. En la imagen, la fachada del edificio Central de la Estaciâ”œâ”‚n aâ”œâ•‘n denominada de "Cappa", aunque pronto serâ”œأ­ ya conocida por su nombre definitivo, "Utrillas", poco despuâ”œآ®s de su reinauguraciâ”œâ”‚n a finales de octubre. Vehâ”œآ،culos a propulsiâ”œâ”‚n de sangre, estacionados en la plaza de acceso junto a la carretera de Zaragoza a Castellâ”œâ”‚n. Fuente visual: Revista "Nuevo Mundo", 1904.', 1904, 1904, 1904, 'Anos 1900', 'SAN JOSâ”œأ«', 41.64036700, -0.86774800, '0101000020E6100000CA6B257497C4EBBF0438BD8BF7D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20454299225.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20454299225.webp', 'https://www.flickr.com/photos/zaragozaantigua/20454299225/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24466, 'C.â”¬â•‘ de la Granja 1977', 'Esta brumosa toma estâ”œأ­ hecha desde uno de los riegos que alimentaban los campos experimentales de la antigua Granja Agrâ”œآ،cola, al lado del Camino que desde Miguel Servet daba entrada principal a la Granja. En primer tâ”œآ®rmino, el cauce de riego. Detrâ”œأ­s, campos de cultivo de herbâ”œأ­ceos de "La Granja". Inmediatamente, los restos el terraplâ”œآ®n del ferrocarril a Utrillas, bifurcado en torno a las ruinas de la fâ”œأ­brica de aglomerados-briquetas MFU, con su chimenea de 1920, a la derecha. A la izquierda, las instalaciones de Viguetas PITAY, S.A., materiales de construcciâ”œâ”‚n. Al fondo, como entre la bruma de las ensoâ”œâ–’aciones, las chimeneas y silos de la abandonada fâ”œأ­brica de cementos Portland de Miraflores. Tras el Camino del Junco y el riego Ribazo del Junco, los postes elâ”œآ®ctricos de la desmantelada lâ”œآ،nea a Utrillas se pierden en el horizonte, y las sombras de la Estaciâ”œâ”‚n de Miraflores parecen desvanecerse. En la actualidad esto serâ”œآ،a aproximadamente la calle Principado de Morea, dando a esos descampados asfaltados donde estuviera el Rastro de la ciudad, que luego fue ocasional aparcamiento multitudinario, y ahora estâ”œأ­ siendo edificado por una inmobiliaria. No deja de ser muy de esta ciudad que tengamos en esta zona una calle dedicada a un medieval pedazo de la Grecia bizantina llamada "Principado de Morea", otra al "Ducado de Atenas", y no haya una calle que recuerde algo de importancia tan capital, como La Granja Agrâ”œآ،cola. Magnificar las glorias del Imperio, sea del color o tamaâ”œâ–’o que sea, tiran mucho. Fuente visual: AVV San Josâ”œآ®.', 1977, 1977, 1977, 'Anos 70', 'SAN JOSâ”œأ«', 41.63749600, -0.86563400, '0101000020E610000000C8091346B3EBBF58AA0B7899D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20073564448.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20073564448.webp', 'https://www.flickr.com/photos/zaragozaantigua/20073564448/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24955, 'Cabezo de Buenavista 1925', 'Imagen capturada en el "restaurant Las Palmeras" sito en el Cabezo de Buenavista, con un posado donde destaca el tenor Miguel Burro Fleta acompaâ”œâ–’ado por su secretario Casaseca, Gayarce, el empresario Casali y su esposa la soprano Marâ”œآ،a Llâ”œأ­cer, la tiple Matilde Revenga y su madre, ademâ”œأ­s de algunos periodistas, amigos y parientes. Este grupo subiâ”œâ”‚ al cabezo a celebrar el â”œآ®xito de la actuaciâ”œâ”‚n que el tenor realizâ”œâ”‚ ante el icono de la Virgen del Pilar en el homâ”œâ”‚nimo templo.', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.63366300, -0.89300300, '0101000020E61000003E5B07077B93ECBFB6D782DE1BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51339041238.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51339041238.webp', 'https://www.flickr.com/photos/zaragozaantigua/51339041238/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24467, 'MFU Utrillas 1980', 'Chimenea de la Fâ”œأ­brica de briquetas levantada en 1920 por la compaâ”œâ–’â”œآ،a "Minas y Ferrocarril de Utrillas, S.A.", para el aprovechamiento integral de los carbones menudos, que aglomerados con breas y alquitranes, se convertâ”œآ،an aquâ”œآ، en bloques de "briqueta", el alimento de las locomotoras de la lâ”œآ،nea. Al fondo, los bloques del 1-3 de la calle Puebla de Hâ”œآ،jar, entre Miguel Servet y el luego prolongado Cesâ”œأ­reo Alierta. A esas alturas de la pelâ”œآ،cula, con la lâ”œآ،nea de Utrillas desmantelada, y la actividad fabril cesada, el entorno quedâ”œâ”‚ para poco mâ”œأ­s que desolaciâ”œâ”‚n, ruina y abandono. La chimenea sobreviviâ”œâ”‚ hasta que fue derribada cuando en 1990 se levantâ”œâ”‚ en esa misma ubicaciâ”œâ”‚n el nuevo Pabellâ”œâ”‚n Municipal de Deportes. La chimenea en sâ”œآ، no molestaba, porque hubiera quedado en uno de los despejados y anchos accesos peatonales. Pero quedaba fea y poco moderna, descontextualizada, justo al lado de uno de los emblemas de la modernidad urbana. Y ya se sabe câ”œâ”‚mo las gastamos en esta ciudad con lo "viejo" cuando vamos de "modernos". Ademâ”œأ­s, como no tenâ”œآ،a inquilinas cigâ”œâ•‌eâ”œâ–’as, que fue lo que salvâ”œâ”‚ a su prima pequeâ”œâ–’a de la Estaciâ”œâ”‚n de Utrillas, pues ni por esas. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/9247284691/in/...', 1980, 1980, 1980, 'Anos 80', 'SAN JOSâ”œأ«', 41.63488200, -0.86691100, '0101000020E6100000705D3123BCBDEBBFD76839D043D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20082307189.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20082307189.webp', 'https://www.flickr.com/photos/zaragozaantigua/20082307189/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24472, 'Calle de Miguel Servet 1984', 'Varias generaciones edilicias capturadas en altura desde el bloque del nâ”¬â•‘ 88 del camino de Cabaldâ”œâ”‚s. De izquierda a derecha: la fâ”œأ­brica Giesa y su acceso por la calle de Joaquâ”œآ،n Guiral; el singular bloque del nâ”¬â•‘ 174-178 de la calle de Miguel Servet, precedido de restos de los antiguos depâ”œâ”‚sitos o estanques de carbâ”œâ”‚n de la Estaciâ”œâ”‚n de Utrillas, levemente sombreados por los bloques del final de la calle de Emilio Castelar, esquina con la de Valentâ”œآ،n Zabala; y el Palacio de Larrinaga.', 1984, 1984, 1984, 'Anos 80', 'SAN JOSâ”œأ«', 41.63745600, -0.86701800, '0101000020E6100000F16261889CBEEBBFCA51802898D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20372082875.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20372082875.webp', 'https://www.flickr.com/photos/zaragozaantigua/20372082875/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24473, 'Briquetas 1976', 'Imagen de las ruinas de la antigua fâ”œأ­brica de briquetas de la lâ”œآ،nea de ferrocarril de Utrillas, como uno de los lugares de "chabolismo" para personas excluidas, "outsiders". Al fondo, los nuevos bloques de viviendas para gente "incluida". Fuente visual: Archivo Pâ”œâ•‘blico Municipal, Gerardo Sancho Ramo.', 1976, 1976, 1976, 'Anos 70', 'SAN JOSâ”œأ«', 41.63586000, -0.86688900, '0101000020E61000007C6308008EBDEBBFD36A48DC63D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20428563241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20428563241.webp', 'https://www.flickr.com/photos/zaragozaantigua/20428563241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24488, 'GIESA c.1984', 'Edificio de la fâ”œأ­brica GIESA en la calle de San Joaquâ”œآ،n, visto desde Miguel Servet. A su puerta accede la vâ”œآ،a ferroviaria que lo comunicaba con la estaciâ”œâ”‚n de Utrillas. A la izquierda, vâ”œآ،a del tranvâ”œآ،a. En 2006, la empresa trasladâ”œâ”‚ sus instalaciones al polâ”œآ،gono Empresarium de La Cartuja Baja. Fuente visual: foto de Mariano Rodrâ”œآ،guez Gonzalvo, en www.facebook.com/photo.php?fbid=478965102268159&set=p...', 1984, 1984, 1984, 'Anos 80', 'SAN JOSâ”œأ«', 41.63948300, -0.86508800, '0101000020E61000007F2F8507CDAEEBBF8AAC3594DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24786828766.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24786828766.webp', 'https://www.flickr.com/photos/zaragozaantigua/24786828766/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24490, 'GIESA 1942', 'Dibujo realizado por los arquitectos Miguel â”œأ¼ngel Navarro y Josâ”œآ® Luis Navarro Anguela en el proyecto de edificaciâ”œâ”‚n de la nueva fâ”œأ­brica de ascensores GIESA (Guiral Industrias Elâ”œآ®ctricas S.A.) Para ubicarla en este emplazamiento, en el km. 2 de la carretera de Castellâ”œâ”‚n, tuvo mucha importancia la inmediatez de la estaciâ”œâ”‚n de ferrocarril de Utrillas, ademâ”œأ­s de las cocheras de los tranvâ”œآ،as de la calle Miguel Servet. Aunque el fin de obra estaba previsto para 1943 (ver alusiâ”œâ”‚n en la puerta, tal y como aparecâ”œآ،a en el proyecto), no se concluyâ”œâ”‚ hasta 1945.', 1942, 1942, 1942, 'Anos 40', 'SAN JOSâ”œأ«', 41.63948300, -0.86488400, '0101000020E610000060ADDA3521ADEBBF8AAC3594DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24812903205.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24812903205.webp', 'https://www.flickr.com/photos/zaragozaantigua/24812903205/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24532, 'Giesa 1942', 'Dibujo del proyecto de Miguel â”œأ¼ngel Navarro Pâ”œآ®rez y Josâ”œآ® Luis Navarro Anguela para las "fâ”œأ­bricas de Giesa" a construir en buena parte de la propiedad de Villa Asunciâ”œâ”‚n, en la carretera de Castellâ”œâ”‚n. Destaca las vâ”œآ،as que por la puerta principal de la factorâ”œآ،a conectarâ”œآ،a con el ferrocarril, y que en el proyecto original no se contemplaba la torre luego aâ”œâ–’adida en el extremo noroeste del gran edificio de acceso.', 1942, 1942, 1942, 'Anos 40', 'SAN JOSâ”œأ«', 41.63922800, -0.86446500, '0101000020E6100000282CF180B2A9EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49500953467.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49500953467.webp', 'https://www.flickr.com/photos/zaragozaantigua/49500953467/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24566, 'La Granja 1930', 'Imagen centrada en tres ejemplares de ganado vacuno lechero de la raza Schwyz guipuzcoana, con sus respectivos cuidadores, ante los establos de la Granja Agrâ”œآ،cola de Zaragoza. Esta raza habâ”œآ،a sido resultado del cruzamiento de la raza indâ”œآ،gena Pirenaica con toros de la suiza raza Schwyz a finales del siglo XIX. Tras varias generaciones, el resultado en tâ”œآ®rminos de trabajo, carne y leche, era mâ”œأ­s que satisfactorio. Este edificio de establos para ganado vacuno estaba situado junto al pabellâ”œâ”‚n de laboratorios. A la derecha, caseta de peones y â”œأ­rboles inmediatos al camino que conectaba con el camino del Puente del Virrey (hacia a la izquierda), y el camino de Cabaldâ”œâ”‚s (hacia la derecha). Fuente visual: exposiciâ”œâ”‚n أ”أ‡آ£La investigaciâ”œâ”‚n agroalimentaria en Aragâ”œâ”‚n. Sus inicios con Rodrâ”œآ،guez Ayusoأ”أ‡أک. Centro de Investigaciâ”œâ”‚n y Tecnologâ”œآ،a Agroalimentaria de Aragâ”œâ”‚n (CITA).', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63758400, -0.86530200, '0101000020E6100000823AE5D18DB0EBBFF7393E5A9CD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15065422956.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15065422956.webp', 'https://www.flickr.com/photos/zaragozaantigua/15065422956/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24569, 'La Granja 1930', 'Imagen centrada en la enseâ”œâ–’anza prâ”œأ­ctica a un grupo de alumnos de la Granja Agrâ”œآ،cola del tratamiento al hongo de la Cercospora beticola, parâ”œأ­sito de la remolacha azucarera, mediante aplicaciones fungicidas con acciâ”œâ”‚n sistâ”œآ®mica. La lecciâ”œâ”‚n estâ”œأ­ siendo impartida en un campo experimental inmediato, al fondo, al camino de Herederos que provenâ”œآ،a del "Despartidero" entre el camino de San Josâ”œآ® y el del Puente del Virrey. Mâ”œأ­s al fondo, el depâ”œâ”‚sito de locomotoras cubierto, chimenea, y otras instalaciones de la estaciâ”œâ”‚n de ferrocarril de Utrillas. Fuente visual: exposiciâ”œâ”‚n أ”أ‡آ£La investigaciâ”œâ”‚n agroalimentaria en Aragâ”œâ”‚n. Sus inicios con Rodrâ”œآ،guez Ayusoأ”أ‡أک/Panel "Los inicios de la Granja Agrâ”œآ،cola en Zaragoza". Centro de Investigaciâ”œâ”‚n y Tecnologâ”œآ،a Agroalimentaria de Aragâ”œâ”‚n (CITA).', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63477000, -0.86770500, '0101000020E6100000F86BB2463DC4EBBFB03DB32440D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20163476559.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20163476559.webp', 'https://www.flickr.com/photos/zaragozaantigua/20163476559/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24570, 'La Granja Aâ”œâ–’os 30', 'Imagen del camino de entrada a la Granja Agrâ”œآ،cola. El del centro era el edificio de Direcciâ”œâ”‚n y Laboratorios. A su izquierda, el edificio de habitaciones del personal residente y bodegas. Al otro extremo, la Escuela Regional de Agricultura. La ordenaciâ”œâ”‚n del espacio es clara, cientâ”œآ،fica, ilustrada. La foto estâ”œأ­ realizada desde el Camino de Cabaldâ”œâ”‚s Fuente visual: AHPZ, Archivo Mora', 1930, 1930, 1939, 'Anos 30', 'SAN JOSâ”œأ«', 41.63666200, -0.86903500, '0101000020E61000001E8A027D22CFEBBF904DF2237ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20180641350.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20180641350.webp', 'https://www.flickr.com/photos/zaragozaantigua/20180641350/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24571, 'La Granja 1913', 'La Granja Escuela Agrâ”œآ،cola Experimental fue inaugurada en 1884 por impulso de la DPZ. Ocupaba 21,5 hectâ”œأ­reas en Miraflores, partida de "Rabalete", en la antigua "Torre de la Infanta". Alfonso XII puso su primera piedra como centro pionero en investigaciâ”œâ”‚n agropecuaria que permitiâ”œâ”‚, entre otras cosas, el "boom" remolachero del Valle del Ebro. Su centro de operaciones fue construido segâ”œâ•‘n proyecto de Fâ”œآ®lix Navarro, con entrada principal por el Camino del Bajo Aragâ”œâ”‚n. Para llegar al punto que ilustra la imagen habâ”œآ،a que cruzar las vâ”œآ،as que conectaban la Estaciâ”œâ”‚n de Utrillas con la de Miraflores. El jovencito que nos ha traâ”œآ،do hasta aquâ”œآ،, 102 aâ”œâ–’os despuâ”œآ®s, estâ”œأ­ parado en la entrada al complejo central para dejarnos contemplar el fabuloso lugar. Mientras, el fotâ”œâ”‚grafo enfoca con tranquilidad desde el Camino de Cabaldâ”œâ”‚s. Al fondo, en el centro, el edificio de Direcciâ”œâ”‚n y Laboratorios, y los cuidados jardines que flanquean el acceso. En la pequeâ”œâ–’a glorieta central del fondo se instalarâ”œأ­, un par de aâ”œâ–’os despuâ”œآ®s, un busto en homenaje a Manuel Rodrâ”œآ،guez Ayuso, Director de la instituciâ”œâ”‚n de 1891 a 1908. A su izquierda, edificio de habitaciones del personal residente y bodegas. Al otro extremo, Escuela Regional de Agricultura y edificio de los establos. La ordenaciâ”œâ”‚n del espacio es clara, higiâ”œآ®nica, cientâ”œآ،fica. Los resultados, invaluables. Asâ”œآ، fue hasta la guerra de 1936-1939. Hoy no queda nada. Fuente visual: Juan Chicoy Arreceigor (1873-1959) www.flickr.com/photos/ricardosanzcortiella/12388250753/in...', 1913, 1913, 1913, 'Anos 10', 'SAN JOSâ”œأ«', 41.63666200, -0.86903500, '0101000020E61000001E8A027D22CFEBBF904DF2237ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20221011172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20221011172.webp', 'https://www.flickr.com/photos/zaragozaantigua/20221011172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24577, 'Granja Agrâ”œآ،cola 1930', 'Imagen del importante Campo de Demostraciâ”œâ”‚n de la Granja Agrâ”œآ،cola de Zaragoza. Aquâ”œآ،, desde 1886, se llevaron a cabo las principales investigaciones prâ”œأ­cticas, experimentaciones y actividades docentes relacionadas con la introducciâ”œâ”‚n en el agro regional de la remolacha azucarera, ademâ”œأ­s de otros cereales y plantas forrajeras, asâ”œآ، como de novedades tâ”œآ®cnicas para mejorar la productividad agrâ”œآ،cola en â”œأ­reas diversas. En la imagen, las parcelas del Campo de Demostraciâ”œâ”‚n quedan localizadas entre la zona de los pabellones principales de la Granja Agrâ”œآ،cola, a la izquierda, junto al camino de Cabaldâ”œâ”‚s, y el empalme ferroviario de Miraflores, a la derecha. Al fondo, emergiendo del arbolado camino principal de acceso a la Granja desde Miguel Servet, las torres del Pilar y la Seo de la vieja ciudad, y el inmediato gran complejo de la estaciâ”œâ”‚n de Utrillas y el cocherâ”œâ”‚n de los Tranvâ”œآ،as. Fuente visual: exposiciâ”œâ”‚n أ”أ‡آ£La investigaciâ”œâ”‚n agroalimentaria en Aragâ”œâ”‚n. Sus inicios con Rodrâ”œآ،guez Ayusoأ”أ‡أک/Panel "Los inicios de la Granja Agrâ”œآ،cola en Zaragoza". Centro de Investigaciâ”œâ”‚n y Tecnologâ”œآ،a Agroalimentaria de Aragâ”œâ”‚n (CITA).', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63477000, -0.86770500, '0101000020E6100000F86BB2463DC4EBBFB03DB32440D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33816735593.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33816735593.webp', 'https://www.flickr.com/photos/zaragozaantigua/33816735593/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24578, 'La Granja 1930', 'Imagen que recoge "las prâ”œأ­cticas por los alumnos becarios de la Inspecciâ”œâ”‚n General de Emigraciâ”œâ”‚n" en la Granja Agrâ”œآ،cola de Zaragoza, en este caso atando fajos de heno de alfalfa que luego serâ”œأ­n recogidos en el carro. La referencia visual, al fondo, de la que fuera casa de Larrinaga nos sitâ”œâ•‘a en el campo de cultivo experimental que limitaba con el camino de la Granja (el paseo arbolado de la izquierda), y con el camino del Bajo Aragâ”œâ”‚n. El camino de la Granja conectaba el camino del Bajo Aragâ”œâ”‚n (al fondo) con los edificios principales de la Granja, atravesando campos agrâ”œآ،colas de experimentaciâ”œâ”‚n y cruzando las vâ”œآ،as del ferrocarril a Utrillas y el empalme a la estaciâ”œâ”‚n de Miraflores, junto a la carbonera y fâ”œأ­brica de briquetas de Minas y Ferrocarriles de Utrillas. Fuente visual: "Granja Agrâ”œآ،cola de Zaragoza. Su cincuentenario. Homenaje y gratitud."', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63666200, -0.86903500, '0101000020E61000001E8A027D22CFEBBF904DF2237ED14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33824637663.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33824637663.webp', 'https://www.flickr.com/photos/zaragozaantigua/33824637663/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24581, 'La Granja 1930', 'Pausa para posado colectivo en la demostraciâ”œâ”‚n prâ”œأ­ctica de trilla mecâ”œأ­nica en terrenos de la Granja Agrâ”œآ،cola durante un cursillo impartido a un grupo de maestros. La trilla mecâ”œأ­nica suponâ”œآ،a un notable avance en las labores de cosecha en el campo, pues con unos pocos obreros encargados de proporcionar y retirar los sacos, la mâ”œأ­quina regulaba la carga y los llenaba de una forma râ”œأ­pida. Esta fue otra de las mumerosas experimentaciones llevadas a cabo en los campos de cultivo de la Granja, incluyendo maquinaria como nunca se habâ”œآ،a visto por los alrededores. Esta imagen se ha capturado en el Campo de Demostraciâ”œâ”‚n entre el camino de Cabaldâ”œâ”‚s y el empalme a la estaciâ”œâ”‚n de Miraflores desde la de Utrillas, cuya carbonera, fâ”œأ­brica de briquetas y chimenea MFU (Minas y Ferrocarriles de Utrillas) destacan al fondo. Fuente visual: "Granja Agrâ”œآ،cola de Zaragoza. Su cincuentenario. Homenaje y gratitud."', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.63477000, -0.86770500, '0101000020E6100000F86BB2463DC4EBBFB03DB32440D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34523567451.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34523567451.webp', 'https://www.flickr.com/photos/zaragozaantigua/34523567451/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24582, 'La Granja 1929', '"Una lecciâ”œâ”‚n prâ”œأ­ctica en el Campo de Demostraciâ”œâ”‚n" de la Granja Agrâ”œآ،cola de Zaragoza, durante la Semana Social Agraria, o demostraciâ”œâ”‚n sobre câ”œâ”‚mo un arado mecâ”œأ­nico puede resultar mâ”œأ­s provechoso, en tâ”œآ®rminos productivos, que uno romano (asâ”œآ، era llamado el de uso tradicional, aunque su procedencia era prehistâ”œâ”‚rica). En la imagen, y tras el moderno artefacto mecâ”œأ­nico, la fâ”œأ­brica de briquetas de Minas y Ferrocarriles de Utrillas, y los postes de madera junto a la lâ”œآ،nea fâ”œآ®rrea del empalme a la estaciâ”œâ”‚n de Miraflores. Un par de estos postes superviven, todavâ”œآ،a, a la masiva extinciâ”œâ”‚n ferroviaria, y siguen en su sitio junto a la ruinosa Torre del camino del Junco. Fuente visual: foto Alejandro de la Barrera, en "Homenaje y testimonio de gratitud que dedican a la Granja Agrâ”œآ،cola de Zaragoza en el Cincuentenario de su fundaciâ”œâ”‚n, los representantes de la Agricultura e Industrias, agradecidas a su benâ”œآ®fico influjo en el resurgimiento de la economâ”œآ،a general aragonesa", 1931.', 1929, 1929, 1929, 'Anos 20', 'SAN JOSâ”œأ«', 41.63477000, -0.86770500, '0101000020E6100000F86BB2463DC4EBBFB03DB32440D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34532197071.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34532197071.webp', 'https://www.flickr.com/photos/zaragozaantigua/34532197071/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24699, 'Miguel Servet 1982', 'Imagen en altura de la calle Miguel Servet (izquierda) y lo que luego serâ”œأ­ la prolongaciâ”œâ”‚n de Cesâ”œأ­reo Alierta (derecha). En medio, la mole del nâ”¬â•‘ 174 de Miguel Servet. A sus pies, las antiguas cocheras de los tranvâ”œآ،as habilitadas como primeras cocheras de los autobuses urbanos. A su derecha, restos de las antiguas carboneras de la estaciâ”œâ”‚n. A la izquierda, los muros de GIESA, y un trozo de Larrinaga. Al fondo, a la derecha, las instalaciones de Viguetas PITAY, S.A., ademâ”œأ­s de los antiguos campos de La Granja, y las chimeneas de la antigua fâ”œأ­brica de cementos de Miraflores. La imagen estâ”œأ­ capturada desde el nuevo bloque de viviendas con entrada por la plaza de Utrillas, construido sobre uno de los antiguos edificios para vivienda de trabajadores de la estaciâ”œâ”‚n de Cappa-Utrillas. Fuente visual: www.facebook.com/photo.php?fbid=10203301013461247&set...', 1982, 1982, 1982, 'Anos 80', 'SAN JOSâ”œأ«', 41.63853000, -0.86592400, '0101000020E6100000C3499A3FA6B5EBBFE8C1DD59BBD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20474151602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20474151602.webp', 'https://www.flickr.com/photos/zaragozaantigua/20474151602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24704, 'Calle de las Minas 1930', 'El barrio de Utrillas se extendâ”œآ،a desde la calle de Miguel Servet, que era a la vez calle y carretera nacional, en el tramo comprendido entre el matadero municipal y la emblemâ”œأ­tica Villa Asunciâ”œâ”‚n, y se vertebraba en seis calles transversales: Escuelas, Utrillas, Minas, Higuera, Belchite y Fillas. Su privilegiada situaciâ”œâ”‚n, entre la estaciâ”œâ”‚n de ferrocarril minero de Utrillas, el macelo, varias industrias, unas escuelas nacionales, y buenos accesos viales, elevâ”œâ”‚ el vecindario a cerca de 1.500 personas, pero su natural expansiâ”œâ”‚n topaba con un cinturâ”œâ”‚n de propiedades particulares que la impedâ”œآ،an. De hecho, las antes referidas calles eran realmente callejones a los que se entraba por Miguel Servet y terminaban en un fondo de saco. La prolongaciâ”œâ”‚n hacia la inmediata y enorme huerta de las Fuentes, de momento, estaba vetada por los propietarios de esos terrenos. Esta circunstancia llevâ”œâ”‚ a redenominar coloquialmente el barrio como "el de las obstrucciones". La imagen ilustra esta situaciâ”œâ”‚n en la calle de las Minas, en una captura realizada desde su emboque por la de Miguel Servet. A la izquierda, las parcelas de los nâ”œâ•‘meros 3, 5 y 7. A la derecha, el nâ”¬â•‘ 6. Al fondo, la parcela que truncaba la continuidad de la calle. A ambos lados, el soleado y el umbrâ”œآ،o, riegos al aire abastecâ”œآ،an los huertos parcelarios.', 1930, 1930, 1930, 'Anos 30', 'SAN JOSâ”œأ«', 41.64293200, -0.86833800, '0101000020E610000034F8FBC56CC9EBBFA4C684984BD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25894157414.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25894157414.webp', 'https://www.flickr.com/photos/zaragozaantigua/25894157414/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24848, 'Miguel Servet 1978', 'Captura de Miguel Servet desde el arranque de la calle de Minas, hasta la difuminaciâ”œâ”‚n al fondo de la actual calle Francisco de Quevedo (ex-Fillas y Camino de Fillas). Aâ”œâ•‘n quedaban mâ”œأ­s de 300 metros para llegar a la entrada a la antigua Estaciâ”œâ”‚n de Utrillas, pero su absoluta trascendencia para esta parte de la ciudad era tal que la denominaciâ”œâ”‚n de bastantes calles de la zona tuvo su raâ”œآ،z en la Lâ”œآ،nea minera que desde 1904 se estableciâ”œâ”‚ entre Zaragoza y Utrillas, y cuya estaciâ”œâ”‚n terminal se localizâ”œâ”‚ en la anterior Estaciâ”œâ”‚n de Cappa. Asâ”œآ،, ya a la izquierda de la imagen quedaba la calle "Utrillas", y la calle "Minas" se referâ”œآ،a, precisamente, a las minas turolenses de lignito de esa localidad. Un poco mâ”œأ­s adelante, la calle "Belchite" hacâ”œآ،a referencia al municipio entonces mâ”œأ­s importante de la lâ”œآ،nea Zaragoza-Utrillas. Bien es cierto que se trataba de calles que nacâ”œآ،an en Miguel Servet, y que desembocaban en la nada, en el "campo", como se decâ”œآ،a entonces, pero es que al actual Barrio de las Fuentes aâ”œâ•‘n le faltaban unas buenas dâ”œآ®cadas para ser tal cosa. Esto formaba parte de la denominada "barriada de Montemolâ”œآ،n", que a finales de los aâ”œâ–’os 60 del pasado siglo en un pleno municipal de los de entonces fue repartida entre los pujantes barrios de Las Fuentes y S. Josâ”œآ®. En la imagen, de izquierda a derecha, el nâ”¬â•‘ 2 de la calle Minas, de 1949. A continuaciâ”œâ”‚n, el nâ”¬â•‘ 71 de Miguel Servet (1949), el nâ”¬â•‘ 73 en plena construcciâ”œâ”‚n (1979), el nâ”¬â•‘ 73 Dpdo. (1964), el nâ”¬â•‘ 75-77 (1971), y el nâ”¬â•‘ 79 (1939). Despuâ”œآ®s de la calle Tomâ”œأ­s Higuera, el nâ”¬â•‘ 81 y el nâ”¬â•‘ 81 Dpdo. (ambos de 1940). Todas las parcelas que continâ”œâ•‘an hasta la calle Belchite serâ”œأ­n luego derribadas, y sobre su solar se levantarâ”œأ­ el nâ”¬â•‘ 83-85 (2007), el nâ”¬â•‘ 87 (1999), y el nâ”¬â•‘ 1 de la calle Belchite (2003). A continuaciâ”œâ”‚n, las obras del nâ”¬â•‘ 2-4 de la calle Belchite (1979), y los edificios del principio de la calle Francisco de Quevedo (nâ”¬â•‘ 1, de 1965, y nâ”¬â•‘ 2, de 1969). Esta calle empezâ”œâ”‚ a ser denominada asâ”œآ، en 1969, ya que antes era la', 1978, 1978, 1978, 'Anos 70', 'SAN JOSâ”œأ«', 41.64257100, -0.86848800, '0101000020E610000087FD9E58A7CAEBBFD32D3BC43FD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20245220822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20245220822.webp', 'https://www.flickr.com/photos/zaragozaantigua/20245220822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24860, 'Miguel Servet 1981', 'Imagen parcial de la zona de salida de las cocheras, en la calle de Miguel Servet, del servicio de los autobuses urbanos gestionados por una empresa concesionaria. Esta ubicaciâ”œâ”‚n fue establecida en las antiguas cocheras de los tranvâ”œآ،as de la ciudad, en servicio hasta enero de 1976, cuando se consumâ”œâ”‚ su progresiva y estudiada sustituciâ”œâ”‚n por lâ”œآ،neas de autobuses que, en lo fundamental, heredaron sus recorridos y rutas. Asâ”œآ،, en la imagen, una unidad de la lâ”œآ،nea 30 "Las Fuentes-Casablanca", que sustituyâ”œâ”‚ a la tranviaria lâ”œآ،nea 15 "Casablanca" (tambiâ”œآ®n "Bajo Aragâ”œâ”‚n-Casablanca"); y una unidad de la lâ”œآ،nea 31 "Torrero-Avda. Goya-Delicias", una de las sustitutivas de la tranviaria lâ”œآ،nea 5 "Venecia-Delicias". Fuente visual: "Andalâ”œأ­n, periâ”œâ”‚dico quincenal aragonâ”œآ®s".', 1981, 1981, 1981, 'Anos 80', 'SAN JOSâ”œأ«', 41.63979900, -0.86618000, '0101000020E610000080608E1EBFB7EBBFBA8102EFE4D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32544728292.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32544728292.webp', 'https://www.flickr.com/photos/zaragozaantigua/32544728292/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24862, 'Calle del Hermano Adolfo c.1988', 'Inâ”œآ®dita imagen capturada en el desolado entorno de la estaciâ”œâ”‚n de Utrillas, y centrada en tres maltratados Pegaso de la flota de autobuses urbanos durmiendo el sueâ”œâ–’o eterno. Carrozados en la factorâ”œآ،a de Icarsa, estuvieron en servicio desde principios de los aâ”œâ–’os 70 hasta mediados de los aâ”œâ–’os 80, siendo sustituidos por nuevos vehâ”œآ،culos Renault. La vida media â”œâ•‘til de los autobuses urbanos, comparada con la de los denostados tranvâ”œآ،as histâ”œâ”‚ricos, era incomparablemente inferior. Tras el muro perimetral de la estaciâ”œâ”‚n y a la derecha, el inmueble del nâ”¬â•‘ 4 de la calle del Hermano Adolfo, medianero con el solar del nâ”¬â•‘ 6, que serâ”œأ­ construido poco despuâ”œآ®s. A la izquierda, la plaza del PIntor Fermâ”œآ،n Aguayo y la calle del Monasterio de Poblet, que comienza al fondo, en la del Monasterio de Samos.', 1988, 1988, 1988, 'Anos 80', 'SAN JOSâ”œأ«', 41.64119200, -0.86844500, '0101000020E6100000B5FD2B2B4DCAEBBF793A579412D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32708080337.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32708080337.webp', 'https://www.flickr.com/photos/zaragozaantigua/32708080337/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24956, 'Cabezo de Buenavista 1925', 'Imagen de la singular terraza del "restaurant" Las Palmeras sito en el cabezo de Buenavista, en el homâ”œâ”‚nimo parque. Gestionado por su propietario, Antonio de Cabo, se convirtiâ”œâ”‚ en uno de los espacios mâ”œأ­s atractivos en los que la "buena sociedad zaragozana" buscaba el "fresco" durante la dura temporada veraniega. El aterrazado entorno, a escasos metros del reciente monumento al rey Alfonso I "El Batallador" (hacia la izquierda de la imagen) presenta una balaustrada que delimita la terraza y el ingreso al restaurante desde un pequeâ”œâ–’o paseo arbolado que en primer tâ”œآ®rmino conectaba con los empinados accesos al cabezo desde la entrada al parque por el sureste, junto al Canal Imperial de Aragâ”œâ”‚n y el chalet Buenavista.', 1925, 1925, 1925, 'Anos 20', 'UNIVERSIDAD', 41.63342300, -0.89280000, '0101000020E610000036CD3B4ED191ECBF61C43E0114D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51346057461.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51346057461.webp', 'https://www.flickr.com/photos/zaragozaantigua/51346057461/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25724, 'Miraflores 1984', 'Tirado por una locomotora elâ”œآ®ctrica de la serie 269 (denominadas las "japonesas" por haber sido ideadas por la Mitsubishi), un tren convencional de pasajeros pasa por la Estaciâ”œâ”‚n de Miraflores en direcciâ”œâ”‚n a la novâ”œآ،sima Estaciâ”œâ”‚n del Portillo. A la izquierda, el modesto pero digno pequeâ”œâ–’o edificio de la estaciâ”œâ”‚n, los andenes de espera con algunos viajeros ocasionales, y con otros tancredos locales, y el mar de vâ”œآ،as encima del balasto. Al fondo, la pasarela peatonal para salvar las vâ”œآ،as, pero que no era muy utilizada al estar las vâ”œآ،as a ras de suelo, y no en trinchera. La electrificaciâ”œâ”‚n ferroviaria llevada a cabo en los aâ”œâ–’os setenta, con sus metros y metros de tendidos aâ”œآ®reos, queda bien patente en la imagen. En la actualidad, el Tercer Cinturâ”œâ”‚n pasa por donde la pasarela peatonal. La original Estaciâ”œâ”‚n fue derribada y levantado otro nuevo edificio que estâ”œأ­ colgado y, a la vez, enterrado. Y todo estâ”œأ­ dentro de un cajâ”œâ”‚n de cemento por encima del cual deberâ”œآ،a llegar Tenor Fleta hasta el Tercer Cinturâ”œâ”‚n, pero no es asâ”œآ،. Tan cerca del centro de la ciudad (tres minutos hasta la Estaciâ”œâ”‚n de Goya), y tan lejos. Todavâ”œآ،a, y han pasado 40 aâ”œâ–’os. Fuente visual: AVV San Josâ”œآ®', 1984, 1984, 1984, 'Anos 80', 'SAN JOSâ”œأ«', 41.63220400, -0.86675000, '0101000020E610000023DBF97E6ABCEBBF4033880FECD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20063440780.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20063440780.webp', 'https://www.flickr.com/photos/zaragozaantigua/20063440780/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25726, 'Cementera Miraflores 1976', 'A la derecha de las vâ”œآ،as del ferrocarril a Barcelona, casi metiendo los zancos en la acequia del Plano, vista crepuscular de câ”œâ”‚mo estaban las cosas por la Estaciâ”œâ”‚n de Miraflores, cuando la mole de la fâ”œأ­brica de cementos Portand de Miraflores, cerrada apenas tres aâ”œâ–’os antes, seguâ”œآ،a hegemonizando el horizonte con sus chimeneas, ya silenciadas, y los silos, vacâ”œآ،os. Cuando fue dinamitada dejâ”œâ”‚ un solar que aâ”œâ•‘n perdura, como los crâ”œأ­teres lunares tras un impacto de meteorito. La metâ”œأ­lica pasarela peatonal sobre las vâ”œآ،as no es que tuviera demasiado uso, que cruzar las vâ”œآ،as a pelo era prâ”œأ­ctica deportiva local, pero no se tiene constancia de que fuera reutilizada en otra ubicaciâ”œâ”‚n cuando en 2002 fue desmantelada para dejar paso al Tercer Cinturâ”œâ”‚n de Ronda. A la original Estaciâ”œâ”‚n de Miraflores le habâ”œآ،an aâ”œâ–’adido un cuerpo extra (puerta y ventana de la izquierda), seâ”œâ–’al de un aumento de funciones que mostraba su buena salud como transiciâ”œâ”‚n de apeadero a Estaciâ”œâ”‚n. En la actualidad esta zona estâ”œأ­ encofrada, alberga una Estaciâ”œâ”‚n de Cercanâ”œآ،as, y pasa el Tercer Cinturâ”œâ”‚n, pero la degradaciâ”œâ”‚n y marasmo urbanâ”œآ،stico de los alrededores son mayâ”œâ•‘sculos. Ah, y no busquen este edificio de la Estaciâ”œâ”‚n: hay otro, colgado, pendiente, suspendido, y muy moderno. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/11123084636/in...', 1976, 1976, 1976, 'Anos 70', 'SAN JOSâ”œأ«', 41.63220400, -0.86675000, '0101000020E610000023DBF97E6ABCEBBF4033880FECD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20091039328.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20091039328.webp', 'https://www.flickr.com/photos/zaragozaantigua/20091039328/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24994, 'San Juan Bosco 1968', 'Imagen capturada en el recinto del Real de la Feria durante la celebraciâ”œâ”‚n de una dominical prueba incluida en el VI Trofeo Federaciâ”œâ”‚n Aragonesa de Ciclismo. Tres ciclistas del equipo Club Aragonâ”œآ®s (Carmelo Blasco, Mario â”œأ¼lvarez y Juan Cofrades) aparecen junto con Jesâ”œâ•‘s Salavera en el circuito que junto a la calle de San Juan Bosco se habilitaba por las calles del recinto donde en las fiestas del Pilar se instalaban las ferias de atracciones. De fondo, la Escuela de Magisterio y el colosal Edificio Torresol en la esquina entre la calle de Tomâ”œأ­s Bretâ”œâ”‚n y la avenida de Valencia. Sobre este espacio se construirâ”œآ،a poco despuâ”œآ®s el Hospital Clâ”œآ،nico.', 1968, 1968, 1968, 'Anos 60', 'UNIVERSIDAD', 41.64285200, -0.90320700, '0101000020E6100000AF95D05D12E7ECBF87156EF948D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52496413294.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52496413294.webp', 'https://www.flickr.com/photos/zaragozaantigua/52496413294/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25728, 'Estaciâ”œâ”‚n de Miraflores 1975', 'Vista del mar de vâ”œآ،as de Miraflores desde la considerable altura del silo de la antigua y vecina fâ”œأ­brica de cementos Portland. Al fondo, el puente del Camino de Cabaldâ”œâ”‚s. Luego, enormes campos de cultivo de herbâ”œأ­ceas, a la izquierda. Una locomotora diâ”œآ®sel elâ”œآ®ctrica 333 de Renfe tirando de un convoy de mercancâ”œآ،as hacia Barcelona, navegando por el ancho mar de vâ”œآ،as de Miraflores. La pasarela peatonal, por encima. El viejito edificio de la estaciâ”œâ”‚n de Miraflores, y la vâ”œآ،a muerta del empalme del ferrocarril de Utrillas. A los pies, inmediato, el gigante recinto de la fâ”œأ­brica de cemento. En la actualidad, el panorama estâ”œأ­ mucho mâ”œأ­s simplificado: la Ronda de Hispanidad, o Tercer Cinturâ”œâ”‚n de Ronda cruza y corta por donde la pasarela peatonal. Los campos de cultivo siguen en barbecho expectante de construcciâ”œâ”‚n, a ver si se rehincha la burbuja esa. El mar de vâ”œآ،as, canalizado en seco por un sarcâ”œâ”‚fago de cemento que espera ser, alguna vez del presente siglo, parte de Tenor Fleta. La Estaciâ”œâ”‚n de Miraflores, tambiâ”œآ®n para Cercanâ”œآ،as, transfigurada sin el viejito edificio, con unas puertas que cuelgan en la nada inaccesible, y unos provisionales accesos alucinantes. Y el solar de la cementera para aparcar, jugar al fâ”œâ•‘tbol, y subir y bajar por piedras. Fuente visual: www.flickr.com/photos/ferrocarril-utrillas/9665677277/in/...', 1975, 1975, 1975, 'Anos 70', 'SAN JOSâ”œأ«', 41.63175500, -0.86579500, '0101000020E61000004D4A41B797B4EBBFD00A0C59DDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20122225378.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20122225378.webp', 'https://www.flickr.com/photos/zaragozaantigua/20122225378/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25729, 'Estaciâ”œâ”‚n de Utrillas 1968', 'La imagen ilustra un momento del proceso de desmantelamiento de la vâ”œآ،a fâ”œآ®rrea Zaragoza-Utrillas, tras el desecamiento del mar de vâ”œآ،as por el que las locomotoras accedâ”œآ،an a los depâ”œâ”‚sitos en que eran guardadas. Esta acciâ”œâ”‚n fue realizada muy poco tiempo despuâ”œآ®s del cierre de la lâ”œآ،nea. Fue tan râ”œأ­pido, que se tuvo que "apartar" al material rodante situado en ellas, que quedâ”œâ”‚ varado como tren fuera de riel, hasta que le llegâ”œâ”‚ su hora. algâ”œâ•‘n tiempo despuâ”œآ®s. El abandono y la degradaciâ”œâ”‚n acabarâ”œأ­n reduciendo a esta estructura, tres dâ”œآ®cadas despuâ”œآ®s, a sus elementos mâ”œأ­s resistentes: los arcos de acceso a los depâ”œâ”‚sitos. Fuente visual: AMZ, Gerardo Sancho Ramo.', 1968, 1968, 1968, 'Anos 60', 'SAN JOSâ”œأ«', 41.63922800, -0.86757100, '0101000020E610000011A8FE4124C3EBBF00581D39D2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20152008289.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20152008289.webp', 'https://www.flickr.com/photos/zaragozaantigua/20152008289/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25732, 'C. Alierta prolongado 1990', 'Foto aâ”œآ®rea de la reciente urbanizaciâ”œâ”‚n del entorno del "Pabellâ”œâ”‚n P. Felipe" y de la prolongaciâ”œâ”‚n de la avenida de Cesâ”œأ­reo Alierta. Falta la conexiâ”œâ”‚n directa por la calle de Cartagena, al fondo, como consecuencia de la demora por el polâ”œآ®mico proceso de expropiaciones de las viviendas de los nâ”œâ•‘meros impares de la calle. El Pabellâ”œâ”‚n municipal de deportes (a la izquierda, fuera de plano) ya habâ”œآ،a sido inaugurado el 17 de abril, y era utilizado como sede de importantes eventos deportivos, como la "Final Four Zaragoza 1990" o final del campeonato de baloncesto de Europa, en la que el equipo KK Jugoplastika Split se proclamâ”œâ”‚ campeâ”œâ”‚n continental. Aâ”œâ•‘n no se ha iniciado, a la derecha, la construcciâ”œâ”‚n de las viviendas y del polâ”œآ®mico Gran Centro Comercial sobre los terrenos de la antigua Estaciâ”œâ”‚n de Utrillas. A la izquierda, las instalaciones deportivas del CDM "La Granja". Fuente visual: FCC', 1990, 1990, 1990, 'Anos 90', 'SAN JOSâ”œأ«', 41.63740800, -0.86800500, '0101000020E61000009F76F86BB2C6EBBFB91AD99596D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20205077096.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20205077096.webp', 'https://www.flickr.com/photos/zaragozaantigua/20205077096/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25747, 'Cocheras Tranvâ”œآ،a 1945', 'Imagen en altura de las cocheras de los Tranvâ”œآ،as en Miguel Servet. Allâ”œآ، se ubicaron desde 1885, y hasta 1976. La inmediatez a la Estaciâ”œâ”‚n de Cappa (luego de Utrillas), hizo que se les conociera al principio, tambiâ”œآ®n, como "Cocheras de Cappa". A la izquierda, el original cocherâ”œâ”‚n de 1885 que albergâ”œâ”‚ las primeras unidades tranviarias de la ciudad. Lo que comenzâ”œâ”‚ siendo una sencilla playa de tres vâ”œآ،as y una placa giratoria para maniobrar, fue sucesivamente ampliada hasta configurar unas enormes instalaciones en las que dar cobijo y reparaciâ”œâ”‚n tranviaria a todas las lâ”œآ،neas, hasta la demoliciâ”œâ”‚n programada de este fundamental, sostenible e impagable servicio pâ”œâ•‘blico. La lâ”œآ،nea del cielo urbana de la â”œآ®poca incluye, al fondo a la izquierda, una visual de la neoclâ”œأ­sica câ”œâ•‘pula de San Fernando, y del mausoleo a los fascistas italianos caâ”œآ،dos durante "la Cruzada". Justo detrâ”œأ­s de las cocheras, imagen parcial del depâ”œâ”‚sito de locomotoras de la Estaciâ”œâ”‚n de Utrillas, y la chimenea de la Estaciâ”œâ”‚n, un poco mâ”œأ­s a la derecha. Este lugar serâ”œأ­ luego la primera ubicaciâ”œâ”‚n de los autobuses urbanos de la ciudad, hasta que la zona sea urbanizada, resultando la construcciâ”œâ”‚n de algunos nuevos bloques de viviendas, y el Colegio Pâ”œâ•‘blico "Tomâ”œأ­s Alvira". Fuente visual: Archivo Construcciones y Auxiliar de Ferrocarriles (DARA-AHPZ)', 1945, 1945, 1945, 'Anos 40', 'SAN JOSâ”œأ«', 41.63947700, -0.86637400, '0101000020E6100000BC5983F755B9EBBFA8C5E061DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20393387742.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20393387742.webp', 'https://www.flickr.com/photos/zaragozaantigua/20393387742/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25753, 'Fâ”œأ­brica de Briquetas 1976', 'Imagen capturada junto a las ruinas de la antigua Fâ”œأ­brica de Briquetas y conglomerados de la MFU (Minas y Ferrocarriles de Utrillas). Al fondo, el desarrollo urbanâ”œآ،stico mediante grandes bloques habitacionales en el entorno de la calle Castelar, Camino de Cabaldâ”œâ”‚s, y Cartagena. Por aquâ”œآ، pasaba el ramal de Utrillas que enlazaba con Miraflores y la fâ”œأ­brica de cementos. Hoy, esta es la calle Ducado de Atenas, junto al CDM "La Granja". Fuente visual: Archivo Pâ”œâ•‘blico Municipal, Gerardo Sancho Ramo, 1976.', 1976, 1976, 1976, 'Anos 70', 'SAN JOSâ”œأ«', 41.63488200, -0.86691100, '0101000020E6100000705D3123BCBDEBBFD76839D043D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20870290524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20870290524.webp', 'https://www.flickr.com/photos/zaragozaantigua/20870290524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25763, 'Miguel Servet 1969', 'Luminosa imagen con el posado de un cobrador tranviario (Pablo Rodrâ”œآ،guez), en el acceso a las cocheras del tranvâ”œآ،a de la calle Miguel Servet. Al fondo, en leve penumbra, y de izquierda a derecha, una unidad de la serie 200, en la lâ”œآ،nea 11 "Parque-San Josâ”œآ®"; la unidad 105 de la lâ”œآ،nea 5 "Venecia-Delicias"; y la unidad 162 de la lâ”œآ،nea 1 "Plaza de San Miguel-Bajo Aragâ”œâ”‚n". Estas cocheras estaban ubicadas cerca de la plaza de Utrillas (en la imagen, hacia la derecha), y la estaciâ”œâ”‚n de ferrocarril de Utrillas (clausurada pocos aâ”œâ–’os antes), cuyo mar de vâ”œآ،as y depâ”œâ”‚sito de locomotoras quedaban detrâ”œأ­s. Fuente visual: Foto John Scragg, a travâ”œآ®s de www.forotrenes.com/', 1969, 1969, 1969, 'Anos 60', 'SAN JOSâ”œأ«', 41.63947700, -0.86637400, '0101000020E6100000BC5983F755B9EBBFA8C5E061DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31211239165.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31211239165.webp', 'https://www.flickr.com/photos/zaragozaantigua/31211239165/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25911, 'Tranvâ”œآ،a Bajo Aragâ”œâ”‚n 1903', 'Unidad 2 del tranvâ”œآ،a elâ”œآ®ctrico de la lâ”œآ،nea del Bajo Aragâ”œâ”‚n, con posado del dueâ”œâ–’o de la empresa, Manuel Escoriaza y Fabro. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œآ® Marâ”œآ،a Sanz Gonzâ”œأ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1903, 1903, 1903, 'Anos 1900', 'SAN JOSâ”œأ«', 41.63947700, -0.86637400, '0101000020E6100000BC5983F755B9EBBFA8C5E061DAD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27403753255.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27403753255.webp', 'https://www.flickr.com/photos/zaragozaantigua/27403753255/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25987, 'Miguel Servet 1956', 'Archivo Josâ”œآ® Mâ”¬آ¬ Borobio. 1956. Imagen aâ”œآ®rea del entorno de la calle Miguel Servet con vistas de la enorme fâ”œأ­brica GIESA, del Colegio Santa Marâ”œآ،a del Pilar (Marianistas) y del palacio de Larrinaga. Al otro lado de la calle, aspecto parcial del descargadero de carbones del ferrocarril de Utrillas, y muros y verja de entrada a la Granja Agrâ”œآ،cola (extremo inferior, a la izquierda). Son visibles las vâ”œآ،as que conectaban a GIESA con la red ferroviaria. Un par de tranvâ”œآ،as, uno por direcciâ”œâ”‚n, avanzan por Miguel Servet. Fuente visual: www.facebook.com/photo.php?fbid=398835526947784&set=p...', 1956, 1956, 1956, 'Anos 50', 'SAN JOSâ”œأ«', 41.63810900, -0.86501200, '0101000020E6100000BFB854A52DAEEBBF4224438EADD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15767299712.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15767299712.webp', 'https://www.flickr.com/photos/zaragozaantigua/15767299712/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (26075, 'Vista aâ”œآ®rea San Josâ”œآ® c.1992', 'Vista aâ”œآ®rea capturada en la zona frontera entre los barrios de Las Fuentes y San Josâ”œآ®, sobrevolando el gran solar de la que fuera estaciâ”œâ”‚n de ferrocarril de Utrillas hasta 1966, delimitada entre la calle de Miguel Servet, el camino de Cabaldâ”œâ”‚s y el esbozo de lo que poco despuâ”œآ®s serâ”œآ،a la calle del Hermano Adolfo, que conecta ambos viales. En primer tâ”œآ®rmino, el gran solar resultante del derribo de casi todas las instalaciones ferroviarias, con los restos del semicircular depâ”œâ”‚sito de locomotoras, la referencial chimenea y los dos grandes pabellones intactos y recayentes a la plaza de Utrillas. Aâ”œâ•‘n habrâ”œآ،an de pasar unos aâ”œâ–’os antes de la impactante intrusiâ”œâ”‚n de una gran superficie comercial incrustada gracias al urbanismo a la carta de la â”œآ®poca.', 1992, 1992, 1992, 'Anos 90', 'SAN JOSâ”œأ«', 41.63970900, -0.86789800, '0101000020E61000001D71C806D2C5EBBF7BFA08FCE1D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52040773202.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52040773202.webp', 'https://www.flickr.com/photos/zaragozaantigua/52040773202/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22276, 'Calle del Brigadier Gasca 1961', 'Imagen parcial de las afecciones de la riada del Ebro en el barrio de la Ortilla capturada en la calle del Brigadier Gasca cerca de su confluencia con la calle del Almutazafe. Al fondo, el camino de Ranillas con la torre de Helios y la chimenea de la antigua fâ”œأ­brica de tratamiento de lanas que emerge entre edificios de vivienda. Fuente visual: AMZ.', 1961, 1961, 1961, 'Anos 60', 'ACTUR-REY FERNANDO', 41.66126400, -0.88339000, '0101000020E61000004DA1F31ABB44ECBFD6027B4CA4D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14962404722.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14962404722.webp', 'https://www.flickr.com/photos/zaragozaantigua/14962404722/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22497, 'Barrio de la Ortilla 1961', 'Imagen capturada durante la antolâ”œâ”‚gica salida de madre o riada del Ebro de enero de 1961, centrada en una barcaza que a fuerza de remo navega por una inundada zona de huerta del barrio de la Ortilla, entre el camino de Ranillas (a la derecha y fuera de plano), la calle de Buenos Aires (donde las parcelas y bloque de viviendas del frente), y las calles de Garcâ”œآ،a Gil y de Paraguay (a espaldas del fotâ”œâ”‚grafo). Sobre la original calle de Valero Ripoll emerge la chimenea de la antigua fabrica de "Manufacturas de lanas de Morâ”œâ”‚n y Anâ”œâ”‚s". Ya en la margen derecha y al fondo se siluetea el templo del Pilar, con la ribereâ”œâ–’a torre de Santa Leonor en proceso de terminaciâ”œâ”‚n, mâ”œأ­s tardana que la de San Francisco de Borja, ya finalizada.', 1961, 1961, 1961, 'Anos 60', 'ACTUR-REY FERNANDO', 41.66353400, -0.88545000, '0101000020E61000004BC8073D9B55ECBF5CE49EAEEED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48962578108.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48962578108.webp', 'https://www.flickr.com/photos/zaragozaantigua/48962578108/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
